// ================================================================
// Helper functions
// ================================================================

export function getPublishedPosts(): BlogPost[] {
  const today = new Date().toISOString().split('T')[0];
  return blogPosts
    .filter((post) => post.publishDate <= today)
    .sort((a, b) => b.publishDate.localeCompare(a.publishDate));
}

export function getPostsByCategory(category: string): BlogPost[] {
  return getPublishedPosts().filter((post) => post.category === category);
}

export function getPostBySlug(slug: string): BlogPost | undefined {
  return blogPosts.find((post) => post.slug === slug);
}

export function getLatestPosts(count: number = 3): BlogPost[] {
  return getPublishedPosts().slice(0, count);
}

export function getRelatedPosts(currentSlug: string, count: number = 2): BlogPost[] {
  const current = getPostBySlug(currentSlug);
  if (!current) return [];
  return getPublishedPosts()
    .filter((post) => post.slug !== currentSlug && post.category === current.category)
    .slice(0, count);
}

export function getAllCategories(): string[] {
  return ['youth', 'families', 'adults', 'couples'];
}

export function getCategoryLabel(category: string, isRTL: boolean): string {
  const labels: Record<string, { en: string; ar: string }> = {
    youth: { en: 'Youth', ar: 'الناشئة' },
    families: { en: 'Families', ar: 'العائلات' },
    adults: { en: 'Adults', ar: 'البالغون' },
    couples: { en: 'Couples', ar: 'الأزواج' },
  };
  return isRTL ? labels[category]?.ar ?? category : labels[category]?.en ?? category;
}
